{"code": "import subprocess, json

# Final check: what repos don't use our ci-cd workflows
r = subprocess.run(["gh", "api", "orgs/Ai-Whisperers/repos?per_page=100"],
                   capture_output=True, text=True, timeout=15)
repos = [r["name"] for r in json.loads(r.stdout) if not r["archived"]]

# Check which have any workflow referencing ci-cd repo
no_cicd = []
for repo in repos:
    if repo in [".github", "AI-Whisperers", "legal", "work-coordination", "ci-cd"]:
        continue
    r2 = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/contents/.github/workflows"],
                        capture_output=True, text=True, timeout=8)
    if r2.returncode == 0:
        wfs = json.loads(r2.stdout)
        if not wfs:
            no_cicd.append(f"{repo:30s} NO workflows")
            continue
        uses_cicd = False
        fnames = [w["name"] for w in wfs if w["type"] == "file"]
        for fn in fnames:
            r3 = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/contents/.github/workflows/{fn}"],
                               capture_output=True, text=True, timeout=8)
            if r3.returncode == 0:
                import base64
                content = base64.b64decode(json.loads(r3.stdout)["content"]).decode()
                if "Ai-Whisperers/ci-cd" in content:
                    uses_cicd = True
                    break
        if not uses_cicd:
            no_cicd.append(f"{repo:30s} NO ci-cd refs ({','.join(fnames[:3])})")
    else:
        no_cicd.append(f"{repo:30s} NO workflows dir")

print(f"Repos without ci-cd integration ({len(no_cicd)}):")
for r in sorted(no_cicd):
    print(f"  {r}")
