    for old, new in file_fixes:
        content = content.replace(old, new)
    with open(f"/tmp/base/{filepath}", "w") as f:
        f.write(content)

# For "content" references that aren't imported, replace the usage patterns
# content.COMPONENT -> "COMPONENT" (locale string, consumer provides)
catalog_files = ["mobile-search", "promo-carousel", "search-autocomplete", "search-filters", "hero-carousel", "category-breadcrumb-jsonld", "category-layout", "brand-filter"]
for cf in catalog_files:
    path = f"/tmp/base/packages/catalog/src/{cf}.tsx"
    if not os.path.exists(path):
        continue
    with open(path) as f:
        content = f.read()

    # Check if it uses content.XXX — replace with a prop or hardcoded string
    if 'content' in content:
        # Find what content properties are used
        props = set()
        for m in re.finditer(r'content\.(\w+)', content):
            props.add(m.group(1))

        # Comment out the import and add a placeholder
        content = re.sub(
            r'^import content from.*$',
            '// content locale strings — consumer provides via props',
            content,
            flags=re.MULTILINE
        )

        # Replace content.PROP with a function fallback
        for prop in props:
            content = content.replace(f'content.{prop}', f'"{prop}"' if prop.isupper() else f'locale?.{prop} || "{prop}"')

        with open(path, "w") as f:
            f.write(content)
        print(f"Fixed {cf}.tsx — removed {len(props)} content refs")

# Same for product and checkout files
for pkg in ["product", "checkout"]:
    import os
    src = f"/tmp/base/packages/{pkg}/src"
    if not os.path.exists(src):
        continue
    for fname in os.listdir(src):
        if not fname.endswith(".tsx"):
            continue
        path = os.path.join(src, fname)
        with open(path) as f:
            content = f.read()

        if "content" in content and "content/es.json" not in content:
            orig = content
            content = re.sub(
